// २. नवीन युजर रजिस्टर करणे
const adduser = async (req, res) => {
    try {
        console.log("Register Body:", req.body);
        res.status(201).json({ message: "User Registered Successfully!" });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
};

// ३. लॉगिन करणे
const loginuser = async (req, res) => {
    try {
        console.log("Login Body:", req.body);
        res.status(200).json({ message: "Login Successful!" });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
};

// ४. सर्व युजर्स शोधणे
const findall = async (req, res) => {
    try {
        res.status(200).json({ message: "All users fetched successfully!" });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
};

// ५. युजर डिलीट करणे
const deleteuser = async (req, res) => {
    try {
        const { _id } = req.params;
        res.status(200).json({ message: `User with ID ${_id} deleted!` });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
};

// ६. युजर प्रोफाइल अपडेट करणे
const updateuser = async (req, res) => {
    try {
        const { _id } = req.params;
        res.status(200).json({ message: `User with ID ${_id} updated!` });
    } catch (err) {
        res.status(500).json({ error: err.message });
    }
};

// ७. सर्व फंक्शन्स एक्सपोर्ट करणे (हे सर्वात महत्त्वाचे आहे)
module.exports = {
    adduser,
    loginuser,
    findall,
    deleteuser,
    updateuser
};
